module shift_register9(
	input wire clk,
	input wire rst,
	input wire en,
	input wire [8:0] D,
	output reg [8:0] Q
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
	if (rst)
		Q <= 9'b000000000;
	else if (en)
		Q <= {Q[7:0], D[0]};
end
endmodule
